from sqlalchemy.orm import Session
from fastapi import HTTPException
from app.models.contact import Contact
from app.schemas.contact import ContactCreate

def create_contact(db: Session, contact_data: ContactCreate) -> Contact:
    db_contact = Contact(**contact_data.model_dump())
    db.add(db_contact)
    db.commit()
    db.refresh(db_contact)
    return db_contact

def list_contacts(db: Session) -> list[Contact]:
    return db.query(Contact).all()

def get_contact_by_id(db: Session, contact_id: int) -> Contact:
    contact = db.query(Contact).filter(Contact.id == contact_id).first()
    if not contact:
        raise HTTPException(status_code=404, detail="Contact not found")
    return contact

def update_contact(db: Session, contact_id: int, contact_data: ContactCreate) -> Contact:
    contact = db.query(Contact).filter(Contact.id == contact_id).first()
    if not contact:
        raise HTTPException(status_code=404, detail="Contact not found")
    for key, value in contact_data.model_dump().items():
        setattr(contact, key, value)
    db.commit()
    db.refresh(contact)
    return contact

def delete_contact(db: Session, contact_id: int) -> None:
    contact = db.query(Contact).filter(Contact.id == contact_id).first()
    if not contact:
        raise HTTPException(status_code=404, detail="Contact not found")
    db.delete(contact)
    db.commit()

